fn main() {
    let args: Vec<String> = env::args().collect();
    if args.len() < 2 {
        eprintln!("Usage: logparse [--json] <file>");
        std::process::exit(1);
    }

    let json_mode = args.contains(&"--json".to_string());
    let file_arg = args.iter().find(|a| !a.starts_with("--") && *a != &args[0]).unwrap();

    let content = fs::read_to_string(file_arg).expect("Failed to read file");
    let entries = parser::parse_log(&content);

    if json_mode {
        println!("{}", output::format_json(&entries));
    } else {
        println!("{}", output::format_summary(&entries));
    }
}
